mapper.select:
SELECT
    r.id as id,
    r.product_id as productId,
    r.customer_id as customerId,
    r.order_id as orderId,
    r.rating as rating,
    r.title as title,
    r.body as body,
    r.verified_purchase as verifiedPurchase,
    r.helpful_count as helpfulCount,
    r.report_count as reportCount,
    r.moderator_notes as moderatorNotes,
    r.state_id as stateId,
    r.created_at as createdAt
FROM product_reviews r

    AND r.id = #{id}
    AND r.product_id = #{productId}
    AND r.customer_id = #{customerId}
    AND r.rating = #{rating}
    AND r.state_id = #{stateId}
    AND r.verified_purchase = #{verifiedPurchase}
    AND r.created_at >= #{startDate}
    AND r.created_at <= #{endDate}

${orderby} ${pagination}

SELECT count(*)
FROM product_reviews r

    AND r.id = #{id}
    AND r.product_id = #{productId}
    AND r.customer_id = #{customerId}
    AND r.rating = #{rating}
    AND r.state_id = #{stateId}
    AND r.verified_purchase = #{verifiedPurchase}
    AND r.created_at >= #{startDate}
    AND r.created_at <= #{endDate}

SELECT r.state_id as stateId, count(*) as count FROM product_reviews r
AND r.state_id = #{stateId}
GROUP BY r.state_id
